size(140);

int n=3;
pen c=black;

void chip(pair center=origin, pen c=c) {
  fill(circle(center, 1), c);
}

void tri(int n=n , int up=1, pen c=c) {
  for (int j=0; j<n; ++j) {
    for (int i=0; i<(n-j); ++i) {
      chip((2*i,0), c);
    }
    currentpicture = shift(-1, -sqrt(3) * up) * currentpicture;
  }
  currentpicture = shift(n, sqrt(3) * up * n) * currentpicture;
}

void sq(int n=n, pen c=c) {
  for (int j=0; j<n; ++j) {
    for (int i=0; i<n; ++i) {
      chip((6*j,6*i), c);
    }
  }
}

